import React from 'react';
import { Link } from 'react-router-dom';
import Button from '../1_atoms/Button';
import './AboutHeroSection.css';

function AboutHeroSection({ title, subtitle, supportText, image, cards }) {
  return (
    <section className="about-hero">
      <div className="about-hero__copy">
        <p className="about-section__eyebrow">Презентация сервиса</p>
        <h1>{title}</h1>
        <p className="about-hero__subtitle">{subtitle}</p>
        <p className="about-hero__text">{supportText}</p>
        <div className="about-hero__actions">
          <Link to="/account">
            <Button>Начать игру</Button>
          </Link>
          <a href="#how-it-works">
            <Button variant="secondary">Как это работает</Button>
          </a>
        </div>
      </div>

      <div className="about-hero__visual">
        <div className="about-hero__image-wrap">
          <img src={image} alt="INSUREKIDS" />
        </div>
        <div className="about-hero__cards">
          {cards.map((card) => (
            <div key={card.title} className="about-floating-card">
              <span>{card.title}</span>
              <strong>{card.text}</strong>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default AboutHeroSection;
